const fs = require('fs');
const { Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell, 
        HeadingLevel, AlignmentType, BorderStyle, WidthType, ShadingType,
        LevelFormat, PageBreak } = require('docx');

// 마크다운 파일 읽기
const markdown = fs.readFileSync('/home/claude/AX_교재_통합본.md', 'utf8');

// 문서 요소 배열
const elements = [];

// 마크다운 파싱 함수
function parseMarkdown(md) {
    const lines = md.split('\n');
    let inCodeBlock = false;
    let codeContent = [];
    let inBlockquote = false;
    let blockquoteContent = [];

    for (let i = 0; i < lines.length; i++) {
        const line = lines[i];

        // 코드 블록 처리
        if (line.startsWith('```')) {
            if (inCodeBlock) {
                // 코드 블록 종료
                elements.push(
                    new Paragraph({
                        children: [new TextRun({
                            text: codeContent.join('\n'),
                            font: "Courier New",
                            size: 20
                        })],
                        shading: { fill: "F5F5F5", type: ShadingType.CLEAR },
                        spacing: { before: 120, after: 120 }
                    })
                );
                codeContent = [];
                inCodeBlock = false;
            } else {
                // 코드 블록 시작
                inCodeBlock = true;
            }
            continue;
        }

        if (inCodeBlock) {
            codeContent.push(line);
            continue;
        }

        // 블록인용 처리
        if (line.startsWith('>')) {
            if (!inBlockquote) {
                inBlockquote = true;
                blockquoteContent = [];
            }
            blockquoteContent.push(line.substring(1).trim());
            continue;
        } else if (inBlockquote && line.trim() === '') {
            // 블록인용 계속
            blockquoteContent.push('');
            continue;
        } else if (inBlockquote) {
            // 블록인용 종료
            elements.push(
                new Paragraph({
                    children: [new TextRun({
                        text: blockquoteContent.join(' '),
                        italics: true,
                        size: 22
                    })],
                    shading: { fill: "E8F4F8", type: ShadingType.CLEAR },
                    spacing: { before: 120, after: 120, line: 360 },
                    indent: { left: 720 }
                })
            );
            blockquoteContent = [];
            inBlockquote = false;
        }

        // 빈 줄
        if (line.trim() === '') {
            elements.push(new Paragraph({ text: '' }));
            continue;
        }

        // 구분선
        if (line.trim() === '---') {
            elements.push(
                new Paragraph({
                    border: {
                        bottom: {
                            color: "CCCCCC",
                            space: 1,
                            style: BorderStyle.SINGLE,
                            size: 6
                        }
                    },
                    spacing: { before: 240, after: 240 }
                })
            );
            continue;
        }

        // 헤딩 처리
        if (line.startsWith('# ')) {
            elements.push(
                new Paragraph({
                    text: line.substring(2),
                    heading: HeadingLevel.HEADING_1,
                    spacing: { before: 480, after: 240 }
                })
            );
        } else if (line.startsWith('## ')) {
            elements.push(
                new Paragraph({
                    text: line.substring(3),
                    heading: HeadingLevel.HEADING_2,
                    spacing: { before: 360, after: 180 }
                })
            );
        } else if (line.startsWith('### ')) {
            elements.push(
                new Paragraph({
                    text: line.substring(4),
                    heading: HeadingLevel.HEADING_3,
                    spacing: { before: 240, after: 120 }
                })
            );
        } else if (line.startsWith('#### ')) {
            elements.push(
                new Paragraph({
                    text: line.substring(5),
                    heading: HeadingLevel.HEADING_4,
                    spacing: { before: 180, after: 90 }
                })
            );
        }
        // 불릿 리스트 (numbered list로 변환)
        else if (line.match(/^(\d+\.)\s/)) {
            const text = line.replace(/^\d+\.\s/, '');
            elements.push(
                new Paragraph({
                    children: parseInlineFormatting(text),
                    numbering: { reference: "numbers", level: 0 },
                    spacing: { before: 60, after: 60 }
                })
            );
        }
        // 불릿 리스트
        else if (line.match(/^[\-\*]\s/)) {
            const text = line.replace(/^[\-\*]\s/, '');
            const indent = (line.match(/^(\s*)/)[1].length / 2) || 0;
            elements.push(
                new Paragraph({
                    children: parseInlineFormatting(text),
                    numbering: { reference: "bullets", level: Math.min(indent, 2) },
                    spacing: { before: 60, after: 60 }
                })
            );
        }
        // 일반 텍스트
        else {
            elements.push(
                new Paragraph({
                    children: parseInlineFormatting(line),
                    spacing: { before: 120, after: 120, line: 360 }
                })
            );
        }
    }

    // 블록인용이 끝까지 남아있는 경우 처리
    if (inBlockquote && blockquoteContent.length > 0) {
        elements.push(
            new Paragraph({
                children: [new TextRun({
                    text: blockquoteContent.join(' '),
                    italics: true,
                    size: 22
                })],
                shading: { fill: "E8F4F8", type: ShadingType.CLEAR },
                spacing: { before: 120, after: 120, line: 360 },
                indent: { left: 720 }
            })
        );
    }
}

// 인라인 포매팅 파싱
function parseInlineFormatting(text) {
    const runs = [];
    let current = '';
    let i = 0;

    while (i < text.length) {
        // 볼드 처리 (**text**)
        if (text.substr(i, 2) === '**') {
            if (current) {
                runs.push(new TextRun({ text: current, size: 24 }));
                current = '';
            }
            const end = text.indexOf('**', i + 2);
            if (end !== -1) {
                runs.push(new TextRun({ 
                    text: text.substring(i + 2, end),
                    bold: true,
                    size: 24
                }));
                i = end + 2;
                continue;
            }
        }
        // 이탤릭 처리 (*text*)
        else if (text[i] === '*' && text[i+1] !== '*') {
            if (current) {
                runs.push(new TextRun({ text: current, size: 24 }));
                current = '';
            }
            const end = text.indexOf('*', i + 1);
            if (end !== -1) {
                runs.push(new TextRun({ 
                    text: text.substring(i + 1, end),
                    italics: true,
                    size: 24
                }));
                i = end + 1;
                continue;
            }
        }
        // 인라인 코드 처리 (`code`)
        else if (text[i] === '`') {
            if (current) {
                runs.push(new TextRun({ text: current, size: 24 }));
                current = '';
            }
            const end = text.indexOf('`', i + 1);
            if (end !== -1) {
                runs.push(new TextRun({ 
                    text: text.substring(i + 1, end),
                    font: "Courier New",
                    size: 22,
                    shading: { fill: "F5F5F5", type: ShadingType.CLEAR }
                }));
                i = end + 1;
                continue;
            }
        }

        current += text[i];
        i++;
    }

    if (current) {
        runs.push(new TextRun({ text: current, size: 24 }));
    }

    return runs.length > 0 ? runs : [new TextRun({ text: text, size: 24 })];
}

// 마크다운 파싱 실행
parseMarkdown(markdown);

// 문서 생성
const doc = new Document({
    styles: {
        default: {
            document: {
                run: { font: "맑은 고딕", size: 24 }
            }
        },
        paragraphStyles: [
            {
                id: "Heading1",
                name: "Heading 1",
                basedOn: "Normal",
                next: "Normal",
                quickFormat: true,
                run: { size: 40, bold: true, font: "맑은 고딕", color: "1F4788" },
                paragraph: { 
                    spacing: { before: 480, after: 240 },
                    outlineLevel: 0
                }
            },
            {
                id: "Heading2",
                name: "Heading 2",
                basedOn: "Normal",
                next: "Normal",
                quickFormat: true,
                run: { size: 34, bold: true, font: "맑은 고딕", color: "2E5C8A" },
                paragraph: { 
                    spacing: { before: 360, after: 180 },
                    outlineLevel: 1
                }
            },
            {
                id: "Heading3",
                name: "Heading 3",
                basedOn: "Normal",
                next: "Normal",
                quickFormat: true,
                run: { size: 30, bold: true, font: "맑은 고딕", color: "3D6FA3" },
                paragraph: { 
                    spacing: { before: 240, after: 120 },
                    outlineLevel: 2
                }
            },
            {
                id: "Heading4",
                name: "Heading 4",
                basedOn: "Normal",
                next: "Normal",
                quickFormat: true,
                run: { size: 26, bold: true, font: "맑은 고딕", color: "4A7EBA" },
                paragraph: { 
                    spacing: { before: 180, after: 90 },
                    outlineLevel: 3
                }
            }
        ]
    },
    numbering: {
        config: [
            {
                reference: "bullets",
                levels: [
                    {
                        level: 0,
                        format: LevelFormat.BULLET,
                        text: "•",
                        alignment: AlignmentType.LEFT,
                        style: {
                            paragraph: {
                                indent: { left: 720, hanging: 360 }
                            }
                        }
                    },
                    {
                        level: 1,
                        format: LevelFormat.BULLET,
                        text: "◦",
                        alignment: AlignmentType.LEFT,
                        style: {
                            paragraph: {
                                indent: { left: 1440, hanging: 360 }
                            }
                        }
                    },
                    {
                        level: 2,
                        format: LevelFormat.BULLET,
                        text: "▪",
                        alignment: AlignmentType.LEFT,
                        style: {
                            paragraph: {
                                indent: { left: 2160, hanging: 360 }
                            }
                        }
                    }
                ]
            },
            {
                reference: "numbers",
                levels: [
                    {
                        level: 0,
                        format: LevelFormat.DECIMAL,
                        text: "%1.",
                        alignment: AlignmentType.LEFT,
                        style: {
                            paragraph: {
                                indent: { left: 720, hanging: 360 }
                            }
                        }
                    }
                ]
            }
        ]
    },
    sections: [{
        properties: {
            page: {
                size: {
                    width: 12240,   // US Letter width
                    height: 15840   // US Letter height
                },
                margin: {
                    top: 1440,
                    right: 1440,
                    bottom: 1440,
                    left: 1440
                }
            }
        },
        children: elements
    }]
});

// 파일로 저장
Packer.toBuffer(doc).then(buffer => {
    fs.writeFileSync("/home/claude/AX_교재_통합본.docx", buffer);
    console.log("✅ 워드 문서 생성 완료: /home/claude/AX_교재_통합본.docx");
});

